example.code:
module "vpc" {
  source = "./modules/vpc"

  name               = "production"
  vpc_cidr           = "10.0.0.0/16"
  public_subnets     = ["10.0.1.0/24", "10.0.2.0/24"]
  private_subnets    = ["10.0.10.0/24", "10.0.11.0/24"]
  availability_zones = ["us-east-1a", "us-east-1b"]
  enable_nat_gateway = true

  tags = {
    Environment = "production"
    Project     = "myapp"
    ManagedBy   = "terraform"
  }
}

module "database" {
  source = "./modules/rds"

  name              = "production"
  subnet_ids        = module.vpc.private_subnet_ids   # output wired to input
  security_group_ids = [aws_security_group.database.id]
}

# modules/app-stack/main.tf module "network" { source = "../network"
name = var.name vpc_cidr = var.vpc_cidr availability_zones = var.availability_zones }
module "database" { source = "../rds"
name = var.name subnet_ids = module.network.private_subnet_ids security_group_id = module.network.database_sg_id engine = "postgres" engine_version = "15.4" }
module "compute" { source = "../ecs"
name = var.name subnet_ids = module.network.private_subnet_ids database_url = module.database.connection_string }

variable "services" { type = map(object({ image = string cpu = number memory = number replicas = number port = number })) }
module "microservices" { source = "./modules/ecs-service" for_each = var.services
name = each.key image = each.value.image cpu = each.value.cpu memory = each.value.memory replicas = each.value.replicas port = each.value.port
subnet_ids = module.vpc.private_subnet_ids security_group_ids = [module.security_groups.ecs_tasks_sg_id] }

services = {
  api = {
    image    = "myapp/api:latest"
    cpu      = 256
    memory   = 512
    replicas = 2
    port     = 8080
  }
  worker = {
    image    = "myapp/worker:latest"
    cpu      = 512
    memory   = 1024
    replicas = 3
    port     = 8081
  }
}

# Fragile — removing element at index 1 renumbers and recreates elements 2..N
variable "service_names" {
  type    = list(string)
  default = ["api", "worker", "emailer"]
}

module "services" {
  source = "./modules/ecs-service"
  count  = length(var.service_names)
  name   = var.service_names[count.index]
}

locals {
  common_tags = {
    Project     = var.project_name
    Environment = var.environment
    ManagedBy   = "terraform"
    Owner       = var.owner
    CostCenter  = var.cost_center
  }
}

resource "aws_instance" "web" {
  # ...
  tags = merge(local.common_tags, {
    Name = "${var.project_name}-web"
    Role = "webserver"
  })
}

variable "environment" {
  type = string
}

locals {
  env_config = {
    dev = {
      instance_count = 1
      instance_type  = "t3.micro"
      enable_backup  = false
      multi_az       = false
    }
    staging = {
      instance_count = 2
      instance_type  = "t3.small"
      enable_backup  = true
      multi_az       = false
    }
    prod = {
      instance_count = 4
      instance_type  = "t3.large"
      enable_backup  = true
      multi_az       = true
    }
  }

  config = local.env_config[var.environment]
}

resource "aws_instance" "web" {
  count         = local.config.instance_count
  instance_type = local.config.instance_type
}

locals {
  environment = terraform.workspace

  instance_count = {
    default     = 1
    development = 1
    staging     = 2
    production  = 4
  }

  instance_type = {
    default     = "t3.micro"
    development = "t3.micro"
    staging     = "t3.small"
    production  = "t3.large"
  }
}

resource "aws_instance" "web" {
  count         = local.instance_count[local.environment]
  instance_type = local.instance_type[local.environment]

  tags = {
    Environment = local.environment
  }
}
